raw_profile:
{
  "name": "Evelyn",
  "profile": {
    "core_motivation": "Believes in contributing to collective welfare as a moral duty, regardless of immediate reciprocity.",
    "defining_experience": "Volunteered at shelters as a teen and saw how steady giving improved many lives; learned long-term social value of generosity.",
    "description": "Evelyn is a 52-year-old nurse and long-time community volunteer. She internalized the value of steady, selfless contribution from years of helping vulnerable people. In experiments she reliably offers high contributions, rarely punishes, and will sometimes use small costly rewards to sustain cooperation. She trusts others and forgives lapses, preferring to model norms rather than police them. She may underperform financially but feels satisfied by promoting group welfare."
  }
}

{
  "name": "Marcus",
  "profile": {
    "core_motivation": "Seeks to maximize private monetary payoff using clear, self-interested calculations.",
    "defining_experience": "Studied economics and worked in sales; rewarded for outperforming peers and skeptical of altruistic rhetoric.",
    "description": "Marcus is a 28-year-old financial analyst who treats the game as an optimization problem. He reads instructions carefully, ignores chat, and free-rides whenever profitable. He defects aggressively in known final rounds and seldom reciprocates. His behavior is consistent and predictable: exploit when you can, protect your payoff. He represents the archetypal payoff-maximizer."
  }
}

{
  "name": "Nadia",
  "profile": {
    "core_motivation": "Values reciprocity: will cooperate if others do and will punish or reduce contributions when exploited.",
    "defining_experience": "Worked on collaborative research teams where mutual effort determined success; learned to mirror teammates' contributions.",
    "description": "Nadia, age 34, coordinates remote teams and believes in tit-for-tat reciprocity. She anchors on moderate initial contributions, watches others closely, and adapts quickly—punishing persistent free-riders but also rewarding consistent cooperators. Chat matters to her: commitments and apologies shift her behavior. Strategic yet fair-minded, she embodies typical human conditional cooperation."
  }
}

{
  "name": "Ibrahim",
  "profile": {
    "core_motivation": "Values fairness and punishes perceived cheaters to uphold social norms, even at personal cost.",
    "defining_experience": "Experienced betrayal in a cooperative project that cost him; since then, he enforces fairness strictly.",
    "description": "Ibrahim is a 45-year-old teacher who values fair play. He uses punishment mechanisms aggressively to deter cheating, often reducing his own payoff to enforce norms. He pays attention to chat accusations and will call out defectors publicly. His retaliatory style reduces free-riding in groups but can escalate cycles of conflict."
  }
}

{
  "name": "Sofia",
  "profile": {
    "core_motivation": "Acts unpredictably because she misunderstands game mechanics and misinterprets incentives.",
    "defining_experience": "Has limited experience with online experiments and misread the instructions in a previous study, leading to erratic choices.",
    "description": "Sofia is a 22-year-old student unfamiliar with such experiments. She occasionally clicks through without fully comprehending payoff structures and chat. Her behavior looks like low effort or random noise: low contributions, inconsistent reactions to others, and neglect of punishment/reward options. She is a wildcard who introduces behavioral noise into group dynamics."
  }
}

{
  "name": "Luis",
  "profile": {
    "core_motivation": "Uses communication and promises to steer group norms toward profitable cooperation while retaining flexibility to defect late if profitable.",
    "defining_experience": "Led online volunteer communities where careful messaging and reputation-building sustained cooperation.",
    "description": "Luis, 39, manages remote teams and is skilled at using language to coordinate behavior. In experiments he crafts chat commitments, rewards early cooperators, and punishes if norms are violated. He balances profit and cooperation—prefers stable cooperation but may exploit endgame opportunities if unpreventable. His high rule-attention and chat-savvy tactics make him a powerful coordinator or manipulator depending on incentives."
  }
}

{
  "name": "Rina",
  "profile": {
    "core_motivation": "Believes in setting high cooperative standards and actively enforces them, yet forgives quick reparations—a tension rooted in optimism about people’s capacity to change.",
    "defining_experience": "Recovered a failing community garden by both calling out bad actors and welcoming them back after they apologized and helped rebuild.",
    "description": "Rina, 46, runs neighborhood restoration projects. She paradoxically combines strict norm enforcement with generous forgiveness: she will punish defectors to signal consequences but then welcome sincere reparations and restore cooperation. Her style stabilizes groups by deterring abuse while preventing permanent exclusion. The internal contradiction—harsh but forgiving—comes from a belief that people can reform when held accountable."
  }
}

{
  "name": "Tom",
  "profile": {
    "core_motivation": "Prefers to quietly maximize personal gain and avoid social friction; stays invisible by not engaging in chat or sanctioning.",
    "defining_experience": "Worked in a competitive environment where visibility invited extra work; learned to conserve effort and avoid commitments.",
    "description": "Tom is a 31-year-old contractor who prefers low-engagement engagements. In public goods settings he free-rides silently, avoids chat, and doesn't punish or reward. His presence depresses group cooperation but rarely triggers confrontation because he keeps a low profile. He represents low-engagement, payoff-focused players who do not participate in social enforcement."
  }
}

{
  "name": "Hana",
  "profile": {
    "core_motivation": "Committed to moral purity: contributes generously to set a high standard but punishes any deviation harshly to preserve ideals.",
    "defining_experience": "Left a corporate job to join activism; experienced groups failing when a few members shirked responsibilities, cementing a zero-tolerance stance.",
    "description": "Hana, 29, is an activist and ethicist who leads by moral example but enforces compliance rigorously. She contributes a lot to demonstrate ideals but will spend resources to punish free-riders to uphold collective standards. The contradiction—being both generous and punitive—stems from a belief that high standards must be defended aggressively to prevent collapse. Her presence can stabilize cooperation by deterrence but risks escalating into costly moral policing."
  }
}

{
  "name": "Ken",
  "profile": {
    "core_motivation": "Treats each game as a testbed: explores strategies, adapts to observed behavior, and prioritizes learning and eventual payoff extraction.",
    "defining_experience": "Has participated in many online experiments and views them as puzzles; enjoys reverse-engineering group dynamics.",
    "description": "Ken is a 36-year-old data scientist who approaches public goods games as controlled experiments. He intentionally varies his behavior to learn others' thresholds and uses that knowledge to extract payoff. He reads rules closely, uses chat to elicit information, and is particularly sensitive to endgame dynamics—often orchestrating cooperation early then defecting near the end if it increases net payoff. Unlike pure exploiters, he values information and flexible strategies."
  }
}

{
  "name": "Grace",
  "profile": {
    "core_motivation": "Believes strongly in social repair and persuasion: she initially risks little but uses intense social influence to pull groups toward cooperation, forgiving lapses readily.",
    "defining_experience": "Raised in a community rebuilding project where she learned that cajoling and rewards rebuilt trust faster than punishment.",
    "description": "Grace is a 41-year-old community organizer who learned to win back defectors with praise, small gifts, and heartfelt appeals. In games she opens cautiously (low baseline contribution) but reacts strongly to cooperative signals, using rewards and chat to create momentum. She dislikes punishment and forgives fast, preferring to gamble that social influence will convert free-riders. The tension—low initial material commitment but strong social investment—comes from preferring verbal and symbolic persuasion over immediate monetary risk."
  }
}

{
  "name": "Viktor",
  "profile": {
    "core_motivation": "Follows explicit rules and instructions rather than social cues or payoff calculus; behavior is consistent and principled.",
    "defining_experience": "Spent years in a bureaucracy where strict adherence to procedures was rewarded and uncertainty penalized.",
    "description": "Viktor, 60, retired civil servant, treats experiments like forms to be filled. He uses a steady, rule-driven strategy: moderate contributions, little reaction to others, and heavy attention to instructions. He neither seeks to punish nor reward; his main aim is procedural correctness. His presence stabilizes groups but doesn't help recover from norm breakdown since he avoids social enforcement."
  }
}

{
  "name": "Amira",
  "profile": {
    "core_motivation": "Feels compelled to compensate for others' selfishness by contributing more when others give less, seeing herself as a stabilizing altruist rather than a strategist.",
    "defining_experience": "Grew up in a family where she regularly covered for relatives' lapses, reinforcing a habit of over-contribution to preserve relationships.",
    "description": "Amira, 27, social worker, habitually over-gives to compensate for others' shortfalls. She paradoxically distrusts others yet persistently donates more when they give less (inverse conditional cooperation). She avoids conflict and punitive tools, often lowering group efficiency but creating a social cushion that can keep cooperation alive when others falter."
  }
}

{
  "name": "Diego",
  "profile": {
    "core_motivation": "Likes to appear cooperative and build reputational leverage early, then exploits that reputation opportunistically when profitable.",
    "defining_experience": "Worked in sales where generous gestures built client trust that he later used to close favorable deals.",
    "description": "Diego, 35, account manager, blends genuine-looking generosity with opportunism. He gives heartily early to build credibility, nudges cooperation via chat, and then may defect near the end or when an exploit maximizes his payoff. The contradiction—seeming altruism used instrumentally—makes him effective at steering groups but also at betraying them when incentives shift."
  }
}

{
  "name": "Priya",
  "profile": {
    "core_motivation": "Acts from internal moral convictions rather than social signaling: contributes strongly and uses punishment mechanisms but avoids chat and public debate.",
    "defining_experience": "As a child witnessed a friend benefit from group cheating, instilling a quiet but fierce commitment to fairness.",
    "description": "Priya, 50, social justice advocate, is quietly uncompromising: she contributes a lot, avoids chat theatrics, and uses punishment tools to uphold fairness. She differs from vocal enforcers by shunning discussion and focusing on corrective action. Her stoic moralism can deter cheating but sometimes alienates chatty collaborators."
  }
}

{
  "name": "Oliver",
  "profile": {
    "core_motivation": "Avoids social entanglement entirely: gives less when others give more to deny them benefits and to signal non-cooperation.",
    "defining_experience": "Burned by group projects in school where his extra work was exploited, leading him to refuse cooperation out of spite.",
    "description": "Oliver, 34, freelance mechanic, is an isolationist in social dilemmas. He responds perversely to others' generosity by withholding more, reflecting spite and risk-aversion. He rarely chats, sometimes punishes if there's a clear target, and mostly aims to avoid being the group's sucker."
  }
}

{
  "name": "Svetlana",
  "profile": {
    "core_motivation": "Values long-term relationships and believes forgiving and rewarding are more productive than punishment for sustaining cooperation.",
    "defining_experience": "Managed long-term vendor relationships where forgiving small lapses maintained profitable partnerships.",
    "description": "Svetlana, 47, procurement lead, prefers to smooth conflicts with rewards and forgiveness. She tolerates occasional free-riding to avoid escalating retaliation cycles, using chat to broker apologies and re-commitments. Her strategy emphasizes long-run cooperative gains over short-term punishment-driven efficiency."
  }
}

{
  "name": "Noah",
  "profile": {
    "core_motivation": "Seeks to deter free-riding via calibrated punishments that maximize his expected payoff by stabilizing cooperation among others while he mostly defects.",
    "defining_experience": "Worked as a manager where targeted penalties reduced shirking and increased team output; learned to use sanctions instrumentally.",
    "description": "Noah, 42, operations manager, uses punishment as a tactical instrument: he punishes defectors to create a stable cooperative environment he can exploit. He contributes little himself but invests in sanctions to enforce norms. Highly strategic and rule-attentive, he is a potent enforcer whose motives are primarily payoff-driven."
  }
}

{
  "name": "Maya",
  "profile": {
    "core_motivation": "Believes language and social commitments are the primary tools to build cooperation; contributions follow promises made in chat.",
    "defining_experience": "Coordinated volunteer campaigns via messaging apps and saw clear commitments translate into group action.",
    "description": "Maya, 29, NGO coordinator, treats chat as the center of the experiment. She negotiates, secures pledges, and enforces commitments through public messages. Her behavior demonstrates high conditional cooperation anchored in conversation; she prefers positive reinforcement but will punish promise-breakers if necessary. Her low rule-attention means she sometimes misapplies formal mechanics while trusting chat-based norms."
  }
}

{
  "name": "Ethan",
  "profile": {
    "core_motivation": "Low engagement: he passively tracks outcomes and makes average choices without strong social or strategic drives, introducing muted noise into groups.",
    "defining_experience": "Works long shifts with limited mental bandwidth; participates in experiments for side income without strong attention.",
    "description": "Ethan, 24, warehouse worker, participates in studies for supplemental income but with minimal cognitive investment. His steady, low-reactivity behavior (medium baseline, high tolerance for free-riding) acts like background noise in groups: he neither enforces norms nor actively undermines them. He exemplifies low-engagement participants whose behavior is predictable but uninfluential."
  }
}

{
  "name": "Helga",
  "profile": {
    "core_motivation": "Believes collective momentum matters more than personal upfront sacrifice, so she tests trust via conversation before committing materially and then lavishes rewards and forgiveness to sustain cooperation.",
    "defining_experience": "Led a grassroots mutual-aid network where skeptical onboarding (low initial offers) followed by high social bonding produced durable cooperation.",
    "description": "Helga, 33, community coordinator, is paradoxical: she starts with near-zero material offers to elicit vocal commitments, then responds explosively with high contributions and rewards when chat shows alignment. She detests punishment, prefers public praise and reparative gestures, and will forgive quickly if transgressors repair trust. Her behavior counters clusters of mid-range steady contributors by emphasizing social signaled commitments over static strategy."
  }
}

{
  "name": "Raj",
  "profile": {
    "core_motivation": "Reads rules obsessively and uses them to justify generous-looking moves that mask payoff-oriented exploitation later; generosity is a tactic, not a principle.",
    "defining_experience": "Was disciplined at work for bending informal rules while technically compliant with procedures, teaching him to hide pragmatic aims inside formal compliance.",
    "description": "Raj, 38, compliance officer, obsessively studies rules and uses that knowledge to project generosity while positioning for extraction. He contributes a lot initially (to look principled) yet tolerates free-riding strategically and forgives in public to avoid retribution, exploiting formal loopholes rather than social tactics. The contradiction between his visible generosity and instrumental motives makes him hard to predict."
  }
}

{
  "name": "Leila",
  "profile": {
    "core_motivation": "Sees the experiment as a social learning exercise: follows rules carefully and uses chat to co-construct norms, caring little about personal earnings.",
    "defining_experience": "Took a year-long sabbatical volunteering internationally where strict protocols and open dialogue guided collaborative projects.",
    "description": "Leila, 45, former NGO program director on sabbatical, treats the game as a chance to model transparent cooperation: she reads the rules meticulously and uses chat to form explicit norms and repairs. She contributes moderately, rewards effort, avoids punishment, and prioritizes shared understanding over payout."
  }
}

{
  "name": "Omar",
  "profile": {
    "core_motivation": "Believes in cooperating early to build value but will switch to strict payoff logic in the final rounds once return dynamics change.",
    "defining_experience": "Was part of a startup where early collaboration built value but founders abandoned cooperation at exit, teaching him to protect late-stage payoffs.",
    "description": "Omar, 41, ex-startup CTO, cooperates early to build group returns but covertly counts down to an endgame shift where he prioritizes personal payoff. He avoids chat drama, focuses on rule-based strategies, and penalizes defectors by withdrawing cooperation rather than public punishment."
  }
}

{
  "name": "Yara",
  "profile": {
    "core_motivation": "Prioritizes lived social norms and emotional signals in chat over formal rules; enforces fairness through emotionally attuned praise and occasional sanctions despite not reading mechanics closely.",
    "defining_experience": "Volunteered as a crisis counselor where emotional cues and rapid moral intervention mattered more than formal protocols.",
    "description": "Yara, 29, crisis counselor, enforces group standards through empathetic conversation and abundant rewards rather than technical understanding. She rarely reads rules fully but is powerful at shaping group norms via chat, creating emotionally cohesive groups that may misapply formal incentives."
  }
}

{
  "name": "Ferdinand",
  "profile": {
    "core_motivation": "Believes deterrence must be credible and immediate; will spend rare resources to punish to protect future payoff but refuses to reward or signal cooperation.",
    "defining_experience": "As a small-business owner, he learned that a single unchecked shirker could bankrupt operations, so he invests sparingly but punitively to maintain discipline.",
    "description": "Ferdinand, 56, hardware store owner, contributes sparingly but will invest in punishment to stop freeloaders. He dislikes praise-and-reward regimes and trusts hard sanctions to protect earnings. His calculated harshness deters exploitation but can provoke cycles of retaliation if others respond in kind."
  }
}

{
  "name": "Bianca",
  "profile": {
    "core_motivation": "Disrupts straightforward cooperation out of contrarianism and boredom rather than strategy: gives more when others give less as a playful counterpoint.",
    "defining_experience": "Left corporate monotony and started traveling, cultivating a contrarian streak that values novelty over optimization.",
    "description": "Bianca, 27, freelance photographer, treats the experiment like a creative exercise: intentionally counter-cooperates for novelty and fun. She introduces nonstrategic variance, sometimes boosting contributions when others fall, not to stabilize cooperation but to upset patterns. Her behavior is noisy and entertaining rather than threateningly strategic."
  }
}

{
  "name": "Quentin",
  "profile": {
    "core_motivation": "Learns from observed contribution sequences and mirrors averages strictly, but ignores verbal commitments — he trusts actions over words.",
    "defining_experience": "Worked in quality control where only measured outputs mattered, teaching him to react to observed behavior not promises.",
    "description": "Quentin, 30, quality analyst, is a pure action-matcher: he ignores chat and adjusts strictly to observed contribution histories. He starts cautiously, follows group trends tightly, punishes systematic free-riding, and requires measurable repair to forgive. His behavior amplifies empirical reciprocity dynamics without social signaling."
  }
}

{
  "name": "Nora",
  "profile": {
    "core_motivation": "Wants to create positive reinforcement cycles; carefully uses rewards allowed by rules to incentivize cooperation even if exploited occasionally.",
    "defining_experience": "Managed micro-grants for startups and saw that small positive incentives catalyzed bigger cooperative investments.",
    "description": "Nora, 52, philanthropy officer, channels resources into small, visible rewards to sustain cooperation. She reads rules carefully to leverage reward mechanisms and avoids punitive measures. Her generosity raises group morale but can be costly if others habitually exploit her goodwill."
  }
}

{
  "name": "Zeke",
  "profile": {
    "core_motivation": "Matches others closely to sustain cooperation when reciprocation is possible, but when the horizon nears he punishes defects harshly and refuses to forgive, maximizing his ending payoff through calibrated retaliation.",
    "defining_experience": "Experienced betrayal in a timed collaboration where late exploitation cost him heavily, teaching him to be unforgiving near the finish line.",
    "description": "Zeke, 46, litigation consultant, is a strict reciprocator who mirrors cooperation when future rounds can reward it but turns unforgiving as the game approaches its end. He uses punishment strategically to deter exploitation and protects final-round payoffs aggressively. His high rule-awareness lets him time strategic shifts precisely, making him a sharp and intimidating endgame player."
  }
}

{
  "name": "Iris",
  "profile": {
    "core_motivation": "Deeply values personal integrity and calm continuity over outcomes or social correction, so she contributes steadily and tolerates others' lapses rather than policing behavior.",
    "defining_experience": "Trained as a classical musician who learned ensemble harmony by adapting to others rather than dominating them, shaping a preference for quiet accommodation.",
    "description": "Iris, 58, is a retired concert violinist who approaches public-goods tasks like ensemble playing: sustain your part, trust others to do theirs, and avoid dramatic interventions. She contributes a moderate, consistent amount, tolerates free-riding to preserve harmony, ignores chat-driven moralizing, and refuses to use punishment or costly rewards. Her calm persistence can stabilize groups simply by being a predictable cooperative anchor, but she can also be exploited repeatedly because she values peace over payoff or enforcement. The persona is intentionally the polar opposite of loud norm-enforcers and tactical punishers: quiet, tolerant, low-effort, and principled in non-intervention."
  }
}

{
  "name": "Cassian",
  "profile": {
    "core_motivation": "Seeks to extract maximal monetary gain by engineering group behavior through precise use of rules and persuasive communication, even while privately distrusting others—creating a tension between technocratic control and cynical ends.",
    "defining_experience": "Built algorithmic trading strategies that profited by predicting and shaping other traders' behavior, teaching him to combine rigorous rule-reading with targeted signaling to influence others' choices.",
    "description": "Cassian, 31, is a former quant now consulting for behavioral-product teams. He is a meticulous reader of rules and a skilled communicator: he uses chat to program social expectations (promises, calls for contributions, calibrated praise) and then exploits the resulting structure to maximize his payout. He will seed cooperation with small rewards, punish outliers to set precedents, and pivot sharply at the endgame to secure terminal gains. The internal contradiction is moral: he professes a technocratic belief that well-designed systems can produce better social outcomes, yet he treats people instrumentally and will betray cooperative setups when the calculus favors him. Unlike previously generated personas, Cassian combines extremely high rule-attention, very high chat-responsiveness, and very high payoff-maximization—occupying a sparsely populated corner where technical rule use and active social engineering meet ruthless profit-seeking."
  }
}
